const records = $.steps.fetchContacts.response.records || [];
const contacts = records.map(r => {
  const fields = r.fields || {};
  return {
    id: r.id,
    name: fields.Name || fields.name || fields['Contact Name'] || 'Unknown',
    email: fields.Email || fields.email || '',
    phone: fields.Phone || fields.phone || '',
    company: fields.Company || fields.company || '',
    notes: fields.Notes || fields.notes || fields.Description || '',
    priority: fields.Priority || fields.priority || 'normal',
    preferredTime: fields['Preferred Time'] || fields.preferredTime || ''
  };
});

let contactSummary = '';
contacts.forEach((c, i) => {
  contactSummary += (i + 1) + '. ' + c.name;
  if (c.company) contactSummary += ' (' + c.company + ')';
  if (c.email) contactSummary += ' - ' + c.email;
  if (c.priority) contactSummary += ' [' + c.priority + ']';
  if (c.preferredTime) contactSummary += ' prefers: ' + c.preferredTime;
  if (c.notes) contactSummary += '\n   Notes: ' + c.notes.slice(0, 200);
  contactSummary += '\n';
});

return { contacts, contactCount: contacts.length, contactSummary };

const now = new Date();
const endDate = new Date(now);
endDate.setDate(now.getDate() + 7);

const todayStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const workStart = $.input.workHoursStart || 9;
const workEnd = $.input.workHoursEnd || 17;

return { timeMin: now.toISOString(), timeMax: endDate.toISOString(), today: todayStr, workStart, workEnd };

const events = $.steps.fetchCalendar.response.items || $.steps.fetchCalendar.response.data || [];
let schedule = '';
let eventCount = 0;

if (Array.isArray(events)) {
  events.forEach((e, i) => {
    const startTime = e.start ? (e.start.dateTime || e.start.date || '') : '';
    const endTime = e.end ? (e.end.dateTime || e.end.date || '') : '';
    schedule += 'EVENT ' + (i + 1) + ': ' + (e.summary || '(no title)') + '\n';
    schedule += '  Start: ' + startTime + ' | End: ' + endTime + '\n';
    eventCount++;
  });
}

return { schedule, eventCount };

const contacts = $.steps.extractContacts.output;
const cal = $.steps.compileSchedule.output;
const dr = $.steps.getDateRange.output;
const duration = $.input.meetingDuration || 30;

let prompt = 'You are an expert scheduling assistant. Suggest optimal meeting times for each contact based on calendar availability and contact preferences.\n\n';
prompt += 'CURRENT DATE: ' + dr.today + '\n';
prompt += 'WORK HOURS: ' + dr.workStart + ':00 to ' + dr.workEnd + ':00\n';
prompt += 'MEETING DURATION: ' + duration + ' minutes each\n\n';
prompt += 'CONTACTS TO SCHEDULE (' + contacts.contactCount + ' contacts):\n';
prompt += contacts.contactSummary + '\n\n';
prompt += 'EXISTING CALENDAR (' + cal.eventCount + ' events):\n';
prompt += cal.schedule + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each contact, suggest 2-3 available time slots\n';
prompt += '- Respect contact preferred times if specified\n';
prompt += '- Prioritize high-priority contacts for prime time slots\n';
prompt += '- Leave buffer time (15 min) between meetings\n';
prompt += '- Avoid scheduling on the same day too densely\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "schedulingSuggestions": [\n';
prompt += '    {\n';
prompt += '      "contactName": "name",\n';
prompt += '      "priority": "high|normal|low",\n';
prompt += '      "suggestedSlots": [{ "day": "Monday", "date": "YYYY-MM-DD", "time": "10:00-10:30", "quality": "ideal|good|okay" }],\n';
prompt += '      "notes": "scheduling notes"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "weekOverview": "summary of the scheduling plan",\n';
prompt += '  "conflicts": ["any scheduling concerns"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { schedulingSuggestions: [], weekOverview: raw, conflicts: [] }; }

const ai = $.steps.parseAI.output;
const contactCount = $.steps.extractContacts.output.contactCount;
const dr = $.steps.getDateRange.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Call Scheduling Suggestions', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Date:* ' + dr.today + ' | *Contacts:* ' + contactCount + ' | *Duration:* ' + ($.input.meetingDuration || 30) + ' min each' } });

if (ai.weekOverview) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:* ' + ai.weekOverview.slice(0, 1800) } });
}
blocks.push({ type: 'divider' });

(ai.schedulingSuggestions || []).forEach((s, i) => {
  const priorityIcon = s.priority === 'high' ? ':red_circle:' : s.priority === 'low' ? ':white_circle:' : ':large_blue_circle:';
  let text = priorityIcon + ' *' + s.contactName + '* [' + s.priority + ']\n';
  (s.suggestedSlots || []).forEach((slot, j) => {
    const qualityIcon = slot.quality === 'ideal' ? ':star:' : slot.quality === 'good' ? ':white_check_mark:' : ':ok:';
    text += '  ' + qualityIcon + ' ' + slot.day + ' ' + slot.date + ' ' + slot.time + '\n';
  });
  if (s.notes) text += '  _' + s.notes + '_\n';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 2900) } });
  if (i < (ai.schedulingSuggestions || []).length - 1) {
    blocks.push({ type: 'divider' });
  }
});

if (ai.conflicts && ai.conflicts.length > 0) {
  blocks.push({ type: 'divider' });
  let conflictText = ':warning: *Scheduling Concerns:*\n';
  ai.conflicts.forEach((c, i) => { conflictText += (i + 1) + '. ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: conflictText.slice(0, 2900) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Airtable + Google Calendar + Claude AI | One CLI' }] });

const fallback = 'Call Scheduling: ' + contactCount + ' contacts - ' + (ai.weekOverview || '').slice(0, 100);
return { blocks, fallback };
